#!/usr/bin/env node
// Fetches Twemoji SVGs and bundles them as base64 data URLs in a TS module.
// Re-run whenever the emoji set changes. The generated file is checked in.
//
//   node apps/site/scripts/twemoji-bundle.mjs

import fs from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const EMOJIS = {
  male: '1f468',       // 👨
  female: '1f469',     // 👩
  person: '1f9d1',     // 🧑 (fallback for ungendered humans)
  robot: '1f916',      // 🤖
  thumbsUp: '1f44d',   // 👍
  lock: '1f512',       // 🔒 — badge for agents with privileged data access
};

const here = path.dirname(fileURLToPath(import.meta.url));
const OUTPUT = path.resolve(here, '../src/components/site/twemoji.ts');

async function fetchSvg(codepoint) {
  const url = `https://raw.githubusercontent.com/jdecked/twemoji/main/assets/svg/${codepoint}.svg`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch ${url}: ${res.status} ${res.statusText}`);
  return await res.text();
}

async function main() {
  const entries = await Promise.all(
    Object.entries(EMOJIS).map(async ([key, cp]) => {
      const svg = await fetchSvg(cp);
      const b64 = Buffer.from(svg, 'utf-8').toString('base64');
      return [key, cp, `data:image/svg+xml;base64,${b64}`];
    })
  );

  const lines = [
    '// AUTO-GENERATED by apps/site/scripts/twemoji-bundle.mjs. Do not edit.',
    '// Source: https://github.com/jdecked/twemoji (MIT license).',
    '',
    'export const TWEMOJI = {',
    ...entries.map(([key, cp, src]) => `  // U+${cp.toUpperCase()}\n  ${key}: '${src}',`),
    '} as const;',
    '',
    'export type TwemojiKey = keyof typeof TWEMOJI;',
    '',
  ];

  await fs.writeFile(OUTPUT, lines.join('\n'), 'utf-8');
  const totalBytes = entries.reduce((n, [, , src]) => n + src.length, 0);
  console.log(`Wrote ${OUTPUT}`);
  console.log(`  ${entries.length} emoji, ~${(totalBytes / 1024).toFixed(1)} KB of inlined base64.`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
